import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Game of Life - Next Generation", () => {
  it.todo("should return empty grid for empty grid");
  it.todo("should return empty grid for single live cell (underpopulation)");
  it.todo("should return empty grid for two live cells (underpopulation)");
  it.todo("should keep a block of four cells alive (still life)");
  it.todo("should transform a vertical blinker to a horizontal blinker");
  it.todo("should revive a dead cell with exactly 3 live neighbors (reproduction)");
  it.todo("should kill a live cell with more than 3 live neighbors (overpopulation)");
});
